#include <stdio.h>
#include <pthread.h>
#include <unistd.h>

/* == EXEMPLE ===============================================
 * volatile avec un signal handler
 * Le handler modifie une variable ; main la surveille.
 * ========================================================= */
#include <signal.h>

volatile sig_atomic_t got_signal = 0;

void handler_example(int sig) {
    (void)sig;
    got_signal = 1;
}

void example_volatile_signal(void) {
    signal(SIGUSR1, handler_example);
    printf("Envoyer SIGUSR1 au PID %d...\n", getpid());
    /* Sans volatile, le compilateur pourrait optimiser cette boucle */
    /* while (got_signal == 0) {} */
    got_signal = 1; /* simulation pour l'exemple */
    printf("Signal recu!\n");
}
/* volatile garantit que got_signal est relu depuis la mémoire */

/* == VOTRE EXERCICE ========================================
 * volatile avec un thread qui modifie un flag.
 * Inspirez-vous de l'exemple avec signal handler.
 * ========================================================= */

volatile int flag = 0;

void *setter(void *arg) {
    (void)arg;
    usleep(100000);
    flag = 1;
    return NULL;
}

int main(void) {
    pthread_t t;
    pthread_create(&t, NULL, setter, NULL);
    printf("Attente du flag...\n");
    while (flag == 0) {
        /* busy wait — volatile force la relecture */
    }
    printf("Flag recu: %d\n", flag);
    pthread_join(t, NULL);
    return 0;
}

